const NewsletterHTML = $input.first().json.content;

// Change 'html' to the name of your specific field
let html = NewsletterHTML || ""; 

// 1. Strip <style> and <script> blocks (including the content inside them)
html = html.replace(/<(style|script)[^>]*>[\s\S]*?<\/\1>/gi, '');

// 2. Strip all remaining HTML tags
html = html.replace(/<[^>]+>/g, '');

// 3. Clean up whitespace and decode basic entities
const cleanText = html
  .replace(/&nbsp;/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// Return the result as a single object
return {
  text_only: cleanText,
  original_html: NewsletterHTML
};

let switch_value = null;

try {
  switch_value = $('Switch').first().json.data["Ready to proceed to next step ?"];
} catch (e) {
  // Node possibly unexecuted; leave as null
}

if (String(switch_value).trim().toLowerCase() == 'Provide Feedback' ) {
  $input.first().json.text = "*📰 AI Generated Subjects for Review with User feedback*";
}

const subjects = $input.first().json.subjects;

// Build the options list
const options = subjects.map(subject => ({
  option: "SUBJECT " + subject.subject_id + ": " + subject.subject
}));

// Add the static final option
options.push({ option: "Add Feedback" });

// Make a form.
$input.first().json.approve_form = [
  {
    fieldLabel: "Newsletter Subject or Feedback",
    fieldType: "radio",
    fieldOptions: {
      values: options
    }
  },
  {
    "fieldLabel": "Editor Feedback for AI",
    "fieldType": "textarea"
  }
];

return $input.all();

const input = $input.first().json.output.data;

const parts = input
  .split('-----')
  .map(p => p.trim())
  .filter(p => p.length > 0);

function extractData(block, filter) {

  // Match subject: value (up to end of line)
  if (filter == "subject") {
    const match = block.match(/Subject_[0-9]*:\s*(.+)/i);
    return match ? match[1].trim() : null;    
  }

  // Match THEME: value (up to end of line)
  const match = block.match(/Subject_([0-9]*)/i);
  return match ? match[1].trim() : null; 
}

// Collect block that contain THEME
const recommendation = parts.filter(block =>
  block.includes("RECOMMENDATION:")
);

// Collect blocks that contain RECOMMENDATION
const themes_raw = parts.filter(block =>
  !block.includes("RECOMMENDATION:")
);

// Build array of objects from the filtered blocks
const result = themes_raw.map(block => ({
  subject: extractData(block, "subject"),
  subject_id: extractData(block, "id"),
  subject_body: block
}));

return [{
  "subjects" : result,
  "recommendation" : recommendation,  
}];

return result;

// Init
let newsletterSubject = null;
let newsletterReviewFeedback = null;

const userSelectedSubject = $('Switch').first().json.data["Newsletter Subject or Feedback"];
const AllSubjects = $('Conditional output').first().json.subjects
const newsletterTextData = $('Process Input').first().json.text_only;

// --- Check for a feedback.
try {
  newsletterReviewFeedback = $input.first().json.data["Editor Notes"];
} catch (e) {}

const SelectedSubject = userSelectedSubject.match(/SUBJECT\s+(\d+)/i);
let subjectNumberID = SelectedSubject ? parseInt(SelectedSubject[1]) : 1;

newsletterSubject = AllSubjects[subjectNumberID - 1];

return [
  {
    "selected_subject" : newsletterSubject,
    "subjects" : AllSubjects,
    "user_review_feedback" : newsletterReviewFeedback,
    "newsletter_text" : newsletterTextData
  }
];

const combinedText = `*📰 Newsletter AI Review*`;
const newsletterReview = $input.first().json.output.data;

const blocks = [
  { type: "divider" },
  {
    type: "section",
    text: {
      type: "mrkdwn",
      text: `\n\n\n Review: \n`
    }
  },
  { type: "divider" },
  {
    type: "section",
    text: {
      type: "mrkdwn",
      text: `\n${newsletterReview}\n`
    }
  },
];

let message = blocks
  .map(b => b.text?.text || '')
  .filter(Boolean)
  .join('\n──────────────────────────────\n\n');

return [
  {
    json: {
      text: combinedText, // fallback full text
      blocks,             // structured Slack Block Kit
      message // flattened message for "Send message and wait for response"
    }
  }
];

// Get the subject.
const formatted_subject = $('Format subject output').first().json.selected_subject.subject;
// Get the review.
const formatted_review = $('Format output - Review').first().json.message

return {
  "formatted_subject" : formatted_subject,
  "formatted_review" : formatted_review
};

let documentId = null;
let formattedTheme = null;
let summaries = null;

/**
 * Recursively walk the entire object tree
 * and collect document, formatted_theme, and summaries
 */
function walk(obj) {
  if (!obj || typeof obj !== 'object') return;

  if (obj.document && !documentId) {
    documentId = obj.document;
  }

  if (obj.formatted_theme && !formattedTheme) {
    formattedTheme = obj.formatted_theme;
  }

  if (obj.summaries && !summaries) {
    summaries = obj.summaries;
  }

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    if (Array.isArray(value)) {
      value.forEach(walk);
    } else if (typeof value === 'object') {
      walk(value);
    }
  }
}

// 1. Workflow Initiated path
try {
  const items = $('Workflow Initiated').all();
  if (items.length > 0) {
    walk(items[0].json);
  }
} catch (e) {
  console.error('Workflow Initiated error:', e);
}

// 2. Chat-trigger fallback
if (!documentId || !formattedTheme || !summaries) {
  try {
    const chatInput = $('When chat message received').first().json.chatInput;
    if (chatInput) {
      const parsed = JSON.parse(chatInput);
      walk(parsed);
    }
  } catch (e) {
    console.error('Chat-trigger error:', e);
  }
}

// 3. Guards
if (!documentId) {
  throw new Error('Document ID not found in any input');
}

if (!formattedTheme) {
  throw new Error('formatted_theme not found in any input');
}

if (!summaries) {
  throw new Error('summaries not found in any input');
}

// 4. Output
return [
  {
    json: {
      inputData: documentId,
      formatted_theme: formattedTheme,
      summaries: summaries
    }
  }
];
